// Read n4.html as template
const template = fs.readFileSync(path.join(__dirname, 'n4.html'), 'utf8');

// Build the kanji data string
const kanjiDataStr = toKanjiJS(DATA);
const total = DATA.length;

let output = template;

// Replace title
output = output.replace('<title>JLPT N4 Practice</title>', '<title>JLPT N1 Practice</title>');

// Replace logo
output = output.replace('JLPT <span>N4</span>', 'JLPT <span>N1</span>');

// Replace stats bar /166
output = output.replace('/166</div>', `/${total}</div>`);

// Replace KANJI DATA comment
output = output.replace('All 166 JLPT N4 Kanji', `All ${total} JLPT N1 Kanji`);

// Replace TOTAL
output = output.replace('const TOTAL = 166;', `const TOTAL = ${total};`);

// Replace the KANJI array (bracket-counting to handle single-line arrays)
const kanji_start = output.match(/const KANJI\s*=\s*\[/);
if (kanji_start) {
  const si = kanji_start.index;
  const bi = si + kanji_start[0].length - 1;
  let depth = 1, ei = bi + 1;
  while (depth > 0 && ei < output.length) {
    if (output[ei] === '[') depth++;
    else if (output[ei] === ']') depth--;
    ei++;
  }
  while (ei < output.length && output[ei] !== ';') ei++;
  output = output.substring(0, si) + `const KANJI = [\n${kanjiDataStr}\n];` + output.substring(ei + 1);
}

// Replace localStorage key
output = output.replace(/jlpt_n4/g, 'jlpt_n1');

// Replace review header
output = output.replace('All 166 Kanji — JLPT N4', `All ${total} Kanji — JLPT N1`);

// Replace filter button
output = output.replace('All (166)', `All (${total})`);

// Replace settings "All" option
output = output.replace('<option value="166">All 166</option>', `<option value="${total}">All ${total}</option>`);

// Replace default kanji display
output = output.replace('>会</div>', '>氏</div>');


// COMPANION_KANJI replacement - bake companion data into output
const compMatch = output.match(/const COMPANION_KANJI\s*=\s*\{/);
if (compMatch) {
  const csi = compMatch.index;
  let cd = 1, cei = csi + compMatch[0].length;
  while (cd > 0 && cei < output.length) { if (output[cei]==='{') cd++; if (output[cei]==='}') cd--; cei++; }
  while (cei < output.length && output[cei] !== ';') cei++;
  output = output.substring(0, csi) + 'const COMPANION_KANJI = ' + JSON.stringify(COMPANION_DATA) + ';' + output.substring(cei + 1);
}

fs.writeFileSync(path.join(__dirname, 'n1.html'), output, 'utf8');
console.log(`Generated n1.html with ${total} kanji entries.`);
